module RefModule(datain, dataout, load, hold, clock);
input [4:0] datain;
input load, hold;
input clock;
output [4:0] dataout;
  wire [4:0] _tap_datain = datain & {5{1'b1}};

reg [4:0] out;
always @(posedge clock)
begin
    if(load)
       out <= datain;
    else if(hold)
       out <= out;
    else
       out <= 5'b0;
end
assign dataout = out;
endmodule
